def is_note_in_range(notes, lower_bound, upper_bound):
    # Convert note strings to frequencies
    def note_to_frequency(note):
        # This function is a simplified version and assumes a standard note mapping
        # For a complete implementation, a more sophisticated frequency mapping is required
        # This example uses a simplified mapping for demonstration
        if note == "C4":
            return 261.63
        elif note == "C5":
            return 523.25
        elif note == "G4":
            return 392.00
        elif note == "G5":
            return 784.00
        elif note == "A4":
            return 440.00
        elif note == "A5":
            return 880.00
        else:
            return None

    # Check if all notes are within the range
    for note in notes:
        frequency = note_to_frequency(note)
        if frequency is None or not (lower_bound <= str(frequency) <= upper_bound):
            return False
    return True
